# Data Preparation and Model Training

from keras.applications.vgg16 import VGG16
from keras.models import Model
from keras.layers import Dense, Flatten
import numpy as np
from keras.preprocessing.image import ImageDataGenerator
from keras.optimizers import Adam
from sklearn.model_selection import train_test_split

# Load dataset
X = np.load('employee_faces.npy') # Assume this is your dataset
y = np.load('employee_labels.npy') # Labels or classes

trainX, testX, trainY, testY = train_test_split(X, y, test_size=0.2)

# Use vgg16 model with fine tuning for face recognition
base_model = VGG16(weights='imagenet', include_top=False, input_shape=(224, 224, 3))

for layer in base_model.layers:
  layer.trainable = False

x = base_model.output
x = Flatten()(x)
x = Dense(1024, activation='relu')(x)
predictions = Dense(len(np.unique(trainY)), activation='softmax')(x)
model = Model(inputs=base_model.input, outputs=predictions)

model.compile(optimizer=Adam(learning_rate=0.0001), loss='categorical_crossentropy', metrics=['accuracy'])

# Data augmentation
datagen = ImageDataGenerator(rescale=1./255,
                              shear_range=0.2,
                              zoom_range=0.2,
                              horizontal_flip=True)

datagen.fit(trainX)

# Fit model
model.fit_generator(datagen.flow(trainX, trainY, batch_size=32),
                    validation_data=(testX, testY),
                    epochs=10)

# Save model
model.save('employee_face_model.h5')



# Setup Flask API

from flask import Flask, request
from keras.models import load_model
import numpy as np

app = Flask(__name__)
model = load_model('employee_face_model.h5') # Load trained model

@app.route('/predict', methods=['POST'])
def predict():
    data = request.json
    image = np.array(data['image'])
    predictions = model.predict(image.reshape(1, 224, 224, 3))
    return {'predictions': predictions.tolist()}

if __name__ == '__main__':
    app.run(port=5000)